211	  }
212	
213	  try {
214	    return normalizeAppSettings(Schema.decodeSync(Schema.fromJsonString(AppSettingsSchema))(value));
215	  } catch {
216	    return DEFAULT_APP_SETTINGS;
217	  }
218	}
