/**
 * Theme definitions for T3 Code.
 *
 * Each theme provides colors for both light and dark modes.
 * The web app applies these as CSS custom properties on the document root.
 */

/** CSS custom property names (without the leading `--`) used by the app's Tailwind theme. */
export interface ThemeColors {
  background: string;
  foreground: string;
  card: string;
  "card-foreground": string;
  popover: string;
  "popover-foreground": string;
  primary: string;
