import { useCallback, useEffect, useSyncExternalStore } from "react";
import {
  getDefaultThemeId,
  getTheme,
  listThemes,
  type ThemeColors,
} from "@t3tools/shared/themes";

type ColorMode = "light" | "dark" | "system";
type ThemeSnapshot = {
  colorMode: ColorMode;
  systemDark: boolean;
  themeId: string;
};

const COLOR_MODE_KEY = "t3code:theme";
const THEME_ID_KEY = "t3code:themeId";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

/** All keys in ThemeColors that we set/remove on the document root. */
const THEME_COLOR_KEYS: ReadonlyArray<keyof ThemeColors> = [
  "background",
  "foreground",
  "card",
  "card-foreground",
  "popover",
  "popover-foreground",
  "primary",
  "primary-foreground",
  "secondary",
  "secondary-foreground",
  "muted",
  "muted-foreground",
  "accent",
  "accent-foreground",
  "destructive",
  "destructive-foreground",
  "border",
  "input",
  "ring",
  "info",
  "info-foreground",
  "success",
  "success-foreground",
  "warning",
  "warning-foreground",
  "sidebar",
  "editor",
  "terminal",
  "status-bar",
];

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeSnapshot | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

function getStoredColorMode(): ColorMode {
  const raw = localStorage.getItem(COLOR_MODE_KEY);
  if (raw === "light" || raw === "dark" || raw === "system") return raw;
  return "system";
}

function getStoredThemeId(): string {
  const raw = localStorage.getItem(THEME_ID_KEY);
  if (raw && getTheme(raw)) return raw;
  return getDefaultThemeId();
}

function resolveMode(colorMode: ColorMode): "light" | "dark" {
  if (colorMode === "system") return getSystemDark() ? "dark" : "light";
  return colorMode;
}

// ---------------------------------------------------------------------------
// DOM application
// ---------------------------------------------------------------------------

function applyThemeColors(themeId: string, resolved: "light" | "dark") {
  const theme = getTheme(themeId);
  const root = document.documentElement;

  if (!theme || theme.isDefault) {
    // Remove all overrides so stylesheet :root / .dark values apply.
    for (const key of THEME_COLOR_KEYS) {
      root.style.removeProperty(`--${key}`);
    }
    root.style.removeProperty("--theme-font-family");
    root.style.removeProperty("--theme-font-size");
    return;
  }

  const palette = theme.colors[resolved];
  for (const key of THEME_COLOR_KEYS) {
    root.style.setProperty(`--${key}`, palette[key]);
  }
  root.style.setProperty("--theme-font-family", theme.fontFamily);
  root.style.setProperty("--theme-font-size", `${String(theme.fontSize)}px`);
}

function applyColorMode(colorMode: ColorMode, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  const isDark = colorMode === "dark" || (colorMode === "system" && getSystemDark());
  document.documentElement.classList.toggle("dark", isDark);

  // Always re-apply theme colors when the mode changes.
  const resolved: "light" | "dark" = isDark ? "dark" : "light";
  applyThemeColors(getStoredThemeId(), resolved);

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash
applyColorMode(getStoredColorMode());

// ---------------------------------------------------------------------------
// External store
// ---------------------------------------------------------------------------

function getSnapshot(): ThemeSnapshot {
  const colorMode = getStoredColorMode();
  const systemDark = colorMode === "system" ? getSystemDark() : false;
  const themeId = getStoredThemeId();

  if (
    lastSnapshot &&
    lastSnapshot.colorMode === colorMode &&
    lastSnapshot.systemDark === systemDark &&
    lastSnapshot.themeId === themeId
  ) {
    return lastSnapshot;
  }

  lastSnapshot = { colorMode, systemDark, themeId };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for system preference changes
  const mq = window.matchMedia(MEDIA_QUERY);
  const handleChange = () => {
    if (getStoredColorMode() === "system") applyColorMode("system", true);
    emitChange();
  };
  mq.addEventListener("change", handleChange);

  // Listen for storage changes from other tabs (color mode AND theme id)
  const handleStorage = (e: StorageEvent) => {
    if (e.key === COLOR_MODE_KEY || e.key === THEME_ID_KEY) {
      applyColorMode(getStoredColorMode(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleChange);
    window.removeEventListener("storage", handleStorage);
  };
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

/** Cached once — the list never changes at runtime. */
const availableThemes = listThemes();

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const { colorMode, themeId } = snapshot;

  const resolvedTheme: "light" | "dark" =
    colorMode === "system" ? (snapshot.systemDark ? "dark" : "light") : colorMode;

  const setTheme = useCallback((next: ColorMode) => {
    localStorage.setItem(COLOR_MODE_KEY, next);
    applyColorMode(next, true);
    emitChange();
  }, []);

  const setThemeId = useCallback((id: string) => {
    if (!getTheme(id)) return;
    localStorage.setItem(THEME_ID_KEY, id);
    applyThemeColors(id, resolveMode(getStoredColorMode()));
    emitChange();
  }, []);

  // Keep DOM in sync on mount/change
  useEffect(() => {
    applyColorMode(colorMode);
  }, [colorMode]);

  return {
    /** Current color-mode preference: "light" | "dark" | "system". */
    theme: colorMode,
    /** Set the color-mode preference. */
    setTheme,
    /** The actually-active mode after resolving "system". */
    resolvedTheme,
    /** The active theme definition id. */
    themeId,
    /** Switch to a different theme by id. */
    setThemeId,
    /** All registered themes. */
    availableThemes,
  } as const;
}

