import type { Theme } from "@t3tools/shared/themes";
import { useTheme } from "~/hooks/useTheme";
import { cn } from "~/lib/utils";

/** Keys shown as color swatches in the preview row. */
const SWATCH_KEYS = ["background", "primary", "accent", "foreground", "destructive"] as const;

function ThemeSwatch({ theme, mode }: { theme: Theme; mode: "light" | "dark" }) {
  const palette = theme.colors[mode];
  return (
    <div className="flex gap-1.5">
      {SWATCH_KEYS.map((key) => (
        <span
          key={key}
          className="size-4 rounded-full border border-border"
          style={{ backgroundColor: palette[key] }}
        />
      ))}
    </div>
  );
}

export function ThemeSelector() {
  const { themeId, setThemeId, availableThemes, resolvedTheme } = useTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Color theme">
      {availableThemes.map((t) => {
        const selected = themeId === t.id;
        return (
          <button
            key={t.id}
            type="button"
            role="radio"
            aria-checked={selected}
            className={cn(
              "flex w-full items-start justify-between rounded-lg border px-3 py-2 text-left transition-colors",
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent",
            )}
            onClick={() => setThemeId(t.id)}
          >
            <span className="flex flex-col gap-1.5">
              <span className="text-sm font-medium">{t.name}</span>
              <ThemeSwatch theme={t} mode={resolvedTheme} />
            </span>
            {selected ? (
              <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                Selected
              </span>
            ) : null}
          </button>
        );
      })}
    </div>
  );
}

